import sys
import math
input = sys.stdin.readline

def solve():
    x, y = map(int, input().split())
    if x <= y:
        if y % x == 0:
            print(y)
        else:
            lcm = x * y // math.gcd(x, y)
            print(lcm)
    else:
        print(x + y)

t = int(input())
for _ in range(t):
    solve()

